  description: 'Zenith Trends - ACM Certificate in us-east-1 for CloudFront',
  tags: {
    Project: 'ZenithTrends',
    Owner: 'Manish Mitra',
    Environment: 'Production',
  },
});

// Main website stack in ap-southeast-2
